query GetAxieDetail($axieId: ID!) {
  axie(axieId: $axieId) {
    ...AxieDetail
    status
    partEvolutionInfo {
      ...AxiePartEvolutionInfo
      __typename
    }
    fortuneSlips {
      total
      collectibles {
        base
        evolved
        name
        __typename
      }
      __typename
    }
    ...AxieDelegationState
    ownerProfile {
      ...ProfileAvatarBrief
      __typename
    }
    delegationState {
      delegateeProfile {
        ...ProfileAvatarBrief
        __typename
      }
      __typename
    }
    forgingAvailableAt
    __typename
  }
}

fragment AxieDetail on Axie {
  ...RequiredAnAxieFields
  ...GeneralOffersInfo
  sireId
  sireClass
  matronId
  matronClass
  axpStatDay {
    ...AxpStat
    __typename
  }
  figure {
    atlas
    model
    image
    __typename
  }
  stats {
    ...AxieStats
    __typename
  }
  order {
    ...OrderInfo
    __typename
  }
  children {
    id
    name
    class
    image
    title
    stage
    newGenes
    hasMysticSuit
    __typename
  }
  potentialPoints {
    beast
    aquatic
    plant
    bug
    bird
    reptile
    mech
    dawn
    dusk
    __typename
  }
  __typename
}

fragment AxieStats on AxieStats {
  hp
  speed
  skill
  morale
  __typename
}

fragment OrderInfo on Order {
  ...PartialOrderFields
  makerProfile {
    name
    addresses {
      ronin
      __typename
    }
    __typename
  }
  assets {
    erc
    address
    id
    quantity
    orderId
    __typename
  }
  __typename
}

fragment PartialOrderFields on Order {
  id
  maker
  kind
  expiredAt
  paymentToken
  startedAt
  basePrice
  endedAt
  endedPrice
  expectedState
  nonce
  marketFeePercentage
  signature
  hash
  duration
  timeLeft
  currentPrice
  suggestedPrice
  currentPriceUsd
  assets {
    erc
    address
    id
    quantity
    orderId
    __typename
  }
  __typename
}

fragment GeneralOffersInfo on TokenAsset {
  ... on Axie {
    yourOffer {
      ...Offer
      __typename
    }
    highestOffer {
      ...Offer
      __typename
    }
    offers(from: 0, size: 10) {
      total
      data {
        ...Offer
        __typename
      }
      __typename
    }
    numActiveOffers
    __typename
  }
  ... on LandPlot {
    yourOffer {
      ...Offer
      __typename
    }
    highestOffer {
      ...Offer
      __typename
    }
    offers(from: 0, size: 10) {
      total
      data {
        ...Offer
        __typename
      }
      __typename
    }
    numActiveOffers
    __typename
  }
  ... on LandItem {
    yourOffer {
      ...Offer
      __typename
    }
    highestOffer {
      ...Offer
      __typename
    }
    offers(from: 0, size: 10) {
      total
      data {
        ...Offer
        __typename
      }
      __typename
    }
    numActiveOffers
    __typename
  }
  __typename
}

fragment Offer on Order {
  ...OrderInfo
  status
  makerProfile {
    ...Profile
    __typename
  }
  __typename
}

fragment Profile on PublicProfile {
